import React, { useContext } from 'react';
import { Container } from 'react-bootstrap'; 
import { Link } from 'react-router-dom'; // Necesario para evitar que el texto del logo sea azul
// Importaciones de Contextos
import { SettingsContext } from '../context/SettingsContext'; 

const Header = () => {
  const { settings } = useContext(SettingsContext);

  // CRÍTICO: Definimos el estilo inline para forzar el redondeo INFERIOR
  const headerStyle = {
    backgroundColor: 'var(--brand-dark)', 
    // Aseguramos que el redondeo superior sea CERO (la parte de arriba es recta)
    borderTopLeftRadius: '0', 
    borderTopRightRadius: '0',
    // Forzamos el redondeo INFERIOR (1.5rem = rounded-2xl)
    borderBottomLeftRadius: '1.5rem', 
    borderBottomRightRadius: '1.5rem',
    paddingTop: '1rem', 
    paddingBottom: '1rem',
  };
  
  return (
    // Aplicamos el estilo inline y la clase stick/z-index
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md" 
      style={headerStyle} 
    >
      <Container> 
        <div className="d-flex justify-content-start align-items-center"> 
          
          {/* 1. Logo de Texto/Eslogan - ESTILOS FINALES */}
          <Link 
            to="/" 
            // flex flex-col para apilar el texto; no-underline para quitar el subrayado azul
            className="flex flex-col items-start h-full no-underline"
          > 
            {/* Nombre: Blanco, grande, negrita, mayúsculas */}
            <span 
              className="text-white text-xl font-extrabold tracking-widest uppercase" 
              style={{ lineHeight: 1 }}
            >
              {settings?.siteName || 'TECNOTITLÁN'}
            </span>
            {/* Eslogan: Gris opaco, pequeño */}
            <span 
              className="text-gray-400 text-xs font-light tracking-wide mt-0.5" 
              style={{ lineHeight: 1 }} 
            >
              Tecnología con Raíces
            </span>
          </Link>
          
          {/* NOTA: El resto del Header (Buscador, Carrito, Usuario) se añadirá en el siguiente paso. */}
          
        </div>
      </Container>
    </header>
  );
};

export default Header;
